const modules: ModuleBlueprint[] = [
  { id: 'm1', title: 'Relational Data Foundations', order: 1, lessons: [
    { id: 'tables-grain', title: 'Tables, rows, columns, and grain', objective: 'Explain what one row represents and why grain controls every trustworthy result.', model: 'A relational table stores observations with a defined grain. Grain is the sentence that explains one row, such as one pharmacy location, one member eligibility period, or one claim line. Every join and aggregation must preserve or intentionally change that grain.', standard: 'Write the grain at the top of every implementation query. Before counting, identify the unique key and test whether the data actually follows it.', mistakes: ['Counting rows without defining grain', 'Assuming a table name reveals its grain', 'Mixing claim headers and claim lines'], scenario: ['Inflated claim total', 'A dashboard doubles paid amount after joining claims to multiple quality measures.', 'Return to grain, aggregate each side to the intended level, then join.'], lab: ['Write the grain for six tables.', 'Identify a candidate key.', 'Run duplicate checks.', 'Explain one grain mismatch.'], sourceKeys: ['postgres', 'sqlite'], visual: [['Table', 'A named relation'], ['Row', 'One observation at declared grain'], ['Column', 'One attribute'], ['Key', 'Identity and relationship']] },
    { id: 'keys-relationships', title: 'Primary keys, foreign keys, and relationships', objective: 'Trace one-to-one, one-to-many, and many-to-many relationships.', model: 'A primary key identifies a row. A foreign key points to a row in another table. One payer can fund many implementations, one implementation can have many milestones, and a many-to-many relationship needs a bridge table.', standard: 'Never join only because columns share a name. Confirm business meaning, uniqueness, data type, and relationship cardinality.', mistakes: ['Joining client_id to payer_id', 'Assuming a foreign key is always populated', 'Skipping bridge tables'], scenario: ['Missing payer mapping', 'A pharmacy exists but has no valid payer relationship.', 'Use a left join from pharmacies to the mapping table and isolate null matches.'], lab: ['Draw the course entity relationship model.', 'Label cardinality.', 'Identify orphan risks.', 'Write one orphan query.'], sourceKeys: ['postgres'], visual: [['Parent key', 'Authoritative identity'], ['Foreign key', 'Reference to parent'], ['Cardinality', 'Expected number of matches'], ['Constraint', 'Enforced integrity when available']] },
    { id: 'normalization', title: 'Normalization and practical denormalization', objective: 'Recognize repeated data, update anomalies, and reporting trade-offs.', model: 'Normalization separates facts so each is maintained once. Denormalized reporting tables intentionally repeat selected values to simplify analytics or improve performance. Neither is inherently superior; the design should match operational and analytical use.', standard: 'Use normalized sources for ownership and controlled updates. Document refresh and lineage when consuming denormalized tables.', mistakes: ['Treating every wide table as wrong', 'Updating repeated attributes in only one row', 'Assuming reporting tables are real-time'], scenario: ['Stale client name', 'A wide release table contains an old client name after CRM correction.', 'Trace lineage and refresh logic instead of manually editing the reporting output.'], lab: ['Identify repeated attributes.', 'Describe update anomaly.', 'Design a normalized alternative.', 'State when a wide view is acceptable.'], sourceKeys: ['postgres', 'duckdb'], visual: [['Operational source', 'Normalized ownership'], ['Transformation', 'Controlled joins'], ['Analytics view', 'Purposeful denormalization'], ['Refresh', 'Documented cadence']] },
    { id: 'data-types', title: 'Data types and semantic integrity', objective: 'Choose and interpret text, numeric, date, timestamp, boolean, and identifier types.', model: 'Data type affects sorting, validation, arithmetic, storage, and comparison. Identifiers that look numeric often belong in text because leading zeros and arithmetic are meaningless. Dates and timestamps require clear timezone assumptions.', standard: 'Define types from business semantics, not sample appearance. Explicitly document timezone, currency, precision, and nullability.', mistakes: ['Storing ZIP codes as numbers', 'Comparing text dates', 'Using floating point for exact money'], scenario: ['Store 00123 becomes 123', 'A numeric field drops leading zeros during ingestion.', 'Model the store identifier as text and validate format separately.'], lab: ['Classify 15 fields.', 'Explain risky type choices.', 'Cast a text date safely.', 'Identify precision needs.'], sourceKeys: ['postgres', 'sqlite'], visual: [['Identifier', 'Usually text'], ['Measure', 'Numeric with precision'], ['Date/time', 'Calendar and timezone'], ['Boolean', 'Explicit true/false state']] },
  ]},
  { id: 'm2', title: 'Reading Schemas and Data Models', order: 2, lessons: [
    { id: 'schema-navigation', title: 'Schemas, catalogs, and object discovery', objective: 'Navigate databases, schemas, tables, views, and metadata.', model: 'A database or catalog groups data objects. Schemas create namespaces inside it. Tables store data, while views expose saved queries. Metadata tables and information schemas reveal columns, types, constraints, and ownership.', standard: 'Inspect metadata before writing a query. Confirm environment, database, schema, and object type.', mistakes: ['Querying the wrong environment', 'Assuming a view is a physical table', 'Using SELECT * to discover production data'], scenario: ['Wrong release table', 'The same table name exists in staging and production schemas.', 'Fully qualify the object and verify current role and context.'], lab: ['List available schemas.', 'Inspect table columns.', 'Identify views.', 'Document fully qualified names.'], sourceKeys: ['postgres', 'snowflake'], visual: [['Account/catalog', 'Top-level data boundary'], ['Database', 'Logical collection'], ['Schema', 'Namespace'], ['Object', 'Table, view, stage, function']] },
    { id: 'erd-reading', title: 'Reading entity relationship diagrams', objective: 'Translate an ERD into join paths and business questions.', model: 'An ERD shows entities, keys, and expected relationships. It does not guarantee the data is clean. Use it as a hypothesis, then test uniqueness and match rates.', standard: 'For every join path, record source key, target key, expected cardinality, and unmatched-record handling.', mistakes: ['Treating ERD lines as proof', 'Ignoring optional relationships', 'Joining across several tables without validating each step'], scenario: ['Launch readiness model', 'The ERD links clients to implementations to milestones.', 'Validate each relationship and calculate match rates before creating the readiness query.'], lab: ['Trace three join paths.', 'Write expected cardinality.', 'Test uniqueness.', 'Measure unmatched rows.'], sourceKeys: ['postgres'], visual: [['Business question', 'What must be answered'], ['Join path', 'Which entities connect'], ['Cardinality test', 'How many matches'], ['Exception review', 'What did not connect']] },
    { id: 'data-dictionary', title: 'Data dictionaries and business definitions', objective: 'Turn ambiguous columns into governed definitions.', model: 'A data dictionary explains meaning, source, type, accepted values, owner, sensitivity, and transformation. Column names such as status or active are not self-explanatory across teams.', standard: 'Link every implementation metric to a definition and owner. Resolve semantic disagreement before building executive reporting.', mistakes: ['Assuming status means the same everywhere', 'Documenting type but not business meaning', 'Leaving derived fields without formulas'], scenario: ['Two active counts', 'Product and implementation teams report different active pharmacy totals.', 'Compare definitions, effective dates, exclusions, and source ownership.'], lab: ['Document ten critical fields.', 'Assign owners.', 'Define accepted values.', 'Write one derived-field formula.'], sourceKeys: ['snowflake', 'informatica'], visual: [['Field name', 'Technical label'], ['Definition', 'Business meaning'], ['Lineage', 'Source and transformation'], ['Owner', 'Decision authority']] },
    { id: 'lineage', title: 'Source-to-target lineage', objective: 'Trace fields through ingestion, transformation, storage, and consumption.', model: 'Lineage identifies where a value originates, how it changes, and where it is used. It supports troubleshooting, governance, impact analysis, and audit evidence.', standard: 'Document field-level transformations for critical data elements and table-level lineage for the broader pipeline.', mistakes: ['Stopping lineage at the warehouse', 'Ignoring manual file edits', 'Documenting only happy-path transformations'], scenario: ['Incorrect payer name', 'A report shows an obsolete payer label.', 'Trace from source through Informatica mapping, Snowflake transformation, and final view.'], lab: ['Choose five critical fields.', 'Trace source to target.', 'Record transformation.', 'Identify failure points.'], sourceKeys: ['informatica', 'snowflake'], visual: [['Source', 'Operational owner'], ['Ingestion', 'File, API, or connector'], ['Transformation', 'Mapping and SQL'], ['Target', 'Curated table'], ['Consumer', 'Product or report']] },
  ]},
  { id: 'm3', title: 'SELECT, WHERE, ORDER BY, and LIMIT', order: 3, lessons: [
    { id: 'select-basics', title: 'Selecting columns and calculated fields', objective: 'Write readable SELECT statements with aliases and expressions.', model: 'SELECT defines the output projection. Explicit columns make intent and dependencies visible. Aliases improve readability, and expressions can derive values without changing source data.', standard: 'Avoid SELECT * in reusable work. Format one selected expression per line and use meaningful aliases.', mistakes: ['Selecting unnecessary sensitive fields', 'Using ambiguous aliases', 'Assuming output order without ORDER BY'], scenario: ['Implementation extract', 'A client needs ID, client name, launch date, and days to launch.', 'Select only required fields and calculate the interval with a clear alias.'], lab: ['Write five SELECT queries.', 'Add aliases.', 'Create one calculation.', 'Remove unnecessary columns.'], sourceKeys: ['postgres', 'sqlite'], visual: [['FROM', 'Available rows and columns'], ['SELECT', 'Chosen output fields'], ['Expression', 'Derived value'], ['Alias', 'Readable output name']] },
    { id: 'where-filters', title: 'Filtering with WHERE', objective: 'Apply comparison, range, membership, pattern, and boolean filters safely.', model: 'WHERE removes rows before grouping. SQL uses three-valued logic, so null comparisons require IS NULL or IS NOT NULL. Parentheses make mixed AND and OR logic explicit.', standard: 'Translate every filter into a plain-language inclusion rule and test edge cases.', mistakes: ['Using = NULL', 'Missing parentheses around OR logic', 'Filtering dates with ambiguous boundaries'], scenario: ['Overdue implementations', 'Find active implementations whose target launch date is before today.', 'Filter active statuses, non-null target dates, and dates earlier than the reporting date.'], lab: ['Find overdue implementations.', 'Filter invalid dates.', 'Use IN for status groups.', 'Test null behavior.'], sourceKeys: ['postgres', 'sqlite'], visual: [['Candidate rows', 'FROM result'], ['Predicate', 'True, false, unknown'], ['WHERE', 'Keep only true'], ['Output', 'Filtered rows']] },
    { id: 'sorting-limiting', title: 'Sorting, limiting, and deterministic results', objective: 'Use ORDER BY and LIMIT without producing unstable conclusions.', model: 'ORDER BY defines result sequence. LIMIT returns only part of that ordered set. Without deterministic tie breakers, repeated queries can return different rows when values tie.', standard: 'When using LIMIT for top or latest records, include a complete ordering that resolves ties.', mistakes: ['Using LIMIT without ORDER BY', 'Sorting text numbers lexically', 'Forgetting NULLS FIRST or LAST behavior'], scenario: ['Latest incidents', 'Two incidents share the same opened timestamp.', 'Add incident_id as a tie breaker after timestamp.'], lab: ['Return top five defect rates.', 'Add tie breaker.', 'Control null ordering.', 'Explain why the result is stable.'], sourceKeys: ['postgres', 'sqlite'], visual: [['Filter', 'Eligible rows'], ['Sort key 1', 'Primary priority'], ['Sort key 2', 'Tie breaker'], ['Limit', 'Requested subset']] },
    { id: 'dates-strings', title: 'Working with dates and text', objective: 'Use date arithmetic and text functions for implementation analysis.', model: 'Date functions support duration, period grouping, and validity checks. Text functions standardize inconsistent labels, trim whitespace, and support pattern matching, but excessive cleanup in every query signals upstream quality debt.', standard: 'Use typed dates, explicit reporting dates, and documented timezone. Preserve raw values while producing normalized fields.', mistakes: ['Relying on implicit date conversion', 'Using current date in reproducibility-sensitive reports', 'Overwriting raw text'], scenario: ['Launch duration', 'Calculate days between kickoff and production.', 'Use typed dates and define handling for missing production dates.'], lab: ['Calculate launch duration.', 'Normalize payer names.', 'Extract year-month.', 'Flag invalid date order.'], sourceKeys: ['postgres', 'duckdb'], visual: [['Raw value', 'Preserved source'], ['Parse', 'Typed date or normalized text'], ['Derive', 'Duration or category'], ['Validate', 'Flag exceptions']] },
  ]},
  { id: 'm4', title: 'Aggregations, GROUP BY, and HAVING', order: 4, lessons: [
    { id: 'aggregate-functions', title: 'Counts, sums, averages, and distinct values', objective: 'Choose aggregate functions and denominators that match the business question.', model: 'Aggregates collapse many rows into summary values. COUNT(*) counts rows, COUNT(column) ignores nulls, and COUNT(DISTINCT column) counts unique non-null values. SUM and AVG inherit the source grain and can be inflated by joins.', standard: 'State numerator, denominator, grain, and null treatment for every metric.', mistakes: ['Using row count as member count', 'Ignoring nulls in denominator', 'Summing after a many-to-many join'], scenario: ['Member count disagreement', 'One report counts eligibility rows and another counts members.', 'Clarify whether the metric is periods, unique members, or active members on a date.'], lab: ['Count rows and distinct members.', 'Calculate claim totals.', 'Compare null behavior.', 'Document metric definition.'], sourceKeys: ['postgres', 'sqlite'], visual: [['Detailed rows', 'Source grain'], ['Aggregate function', 'Count, sum, average'], ['Grouping key', 'Summary level'], ['Metric', 'Defined result']] },
    { id: 'group-by', title: 'Grouping by business dimensions', objective: 'Summarize data by client, payer, month, and status.', model: 'GROUP BY creates one result row per unique combination of grouped expressions. Every selected non-aggregate expression must belong to the grouping level.', standard: 'Write the intended output grain before the query and include only dimensions needed at that level.', mistakes: ['Selecting ungrouped detail columns', 'Grouping by too many fields', 'Using positional GROUP BY in maintained queries'], scenario: ['Monthly claim totals', 'Leadership needs payer-month paid amount.', 'Group by payer and a documented month expression, not claim date detail.'], lab: ['Aggregate claims by payer-month.', 'Count implementations by status.', 'Calculate average duration by client.', 'Verify output grain.'], sourceKeys: ['postgres', 'duckdb'], visual: [['Rows', 'Detailed events'], ['Group keys', 'Client, payer, month'], ['Buckets', 'Unique combinations'], ['Aggregates', 'Metrics per bucket']] },
    { id: 'having', title: 'Filtering groups with HAVING', objective: 'Distinguish row filters from aggregate filters.', model: 'WHERE filters input rows before aggregation. HAVING filters grouped results after aggregates are calculated. Moving a condition between them can change both meaning and performance.', standard: 'Use WHERE for source eligibility and HAVING for conditions on aggregate results.', mistakes: ['Using HAVING for every filter', 'Filtering failed rows after calculating rates', 'Confusing count threshold with row predicate'], scenario: ['High-defect clients', 'Find clients with defect rate above five percent.', 'Filter eligible defects and releases in WHERE, group by client, then apply the calculated threshold in HAVING.'], lab: ['Find clients with more than three defects.', 'Compare WHERE and HAVING.', 'Explain changed denominator.', 'Add a minimum volume rule.'], sourceKeys: ['postgres', 'sqlite'], visual: [['WHERE', 'Filter input rows'], ['GROUP BY', 'Create groups'], ['Aggregate', 'Calculate metrics'], ['HAVING', 'Filter groups']] },
    { id: 'conditional-aggregation', title: 'Conditional aggregation and operational scorecards', objective: 'Build multiple metrics from one grouped dataset.', model: 'Conditional aggregation uses CASE inside SUM or COUNT to calculate counts and rates for categories such as passed, failed, overdue, or missing. It reduces repeated scans and keeps denominator logic together.', standard: 'Make conditions mutually exclusive when categories should sum to the total, and test uncategorized rows.', mistakes: ['Overlapping category conditions', 'Integer division in rate calculations', 'No ELSE handling'], scenario: ['Release scorecard', 'Create pass, warning, and fail counts by client.', 'Use conditional counts and expose an uncategorized count as a quality check.'], lab: ['Build release scorecard.', 'Calculate pass rate.', 'Add unknown category.', 'Validate category totals.'], sourceKeys: ['postgres', 'duckdb'], visual: [['Group', 'Client or release'], ['CASE', 'Classify rows'], ['SUM', 'Count each class'], ['Rate', 'Divide by controlled denominator']] },
  ]},
  { id: 'm5', title: 'Joins and Relationship Troubleshooting', order: 5, lessons: [
    { id: 'inner-left', title: 'INNER and LEFT joins', objective: 'Choose join type based on whether unmatched source rows must remain visible.', model: 'INNER JOIN returns matched combinations. LEFT JOIN preserves every row from the left side and fills unmatched right-side columns with null. The choice encodes a business rule, not a stylistic preference.', standard: 'Name the driving table and explicitly decide how unmatched rows should appear.', mistakes: ['Using INNER JOIN and hiding missing mappings', 'Filtering right-side fields in WHERE after a LEFT JOIN', 'Not measuring match rate'], scenario: ['Missing payer mappings', 'Identify pharmacies without a mapping.', 'Start from pharmacies, left join mappings, and filter where the mapping key is null.'], lab: ['Join clients to implementations.', 'Find unmapped pharmacies.', 'Measure match rate.', 'Explain driving table.'], sourceKeys: ['postgres', 'sqlite'], visual: [['Left source', 'Rows to preserve'], ['Join condition', 'Business key match'], ['Matches', 'Combined rows'], ['Unmatched', 'Null right-side fields']] },
    { id: 'full-anti', title: 'FULL joins and anti-joins for reconciliation', objective: 'Compare two populations and classify source-only, target-only, and matched records.', model: 'A FULL OUTER JOIN preserves both sides and exposes missing records in either direction. Anti-join patterns isolate rows with no match. SQLite learners can emulate full reconciliation with UNION patterns.', standard: 'Classify every record into matched, source-only, target-only, or conflicting.', mistakes: ['Comparing only total counts', 'Ignoring duplicate keys before reconciliation', 'Treating target-only rows as harmless'], scenario: ['Source-target release mismatch', 'Source has 10,020 rows and target has 10,018.', 'Reconcile by stable key and classify exact missing or extra records.'], lab: ['Build reconciliation query.', 'Classify row status.', 'Count categories.', 'List conflicting attributes.'], sourceKeys: ['postgres', 'sqlite'], visual: [['Source keys', 'Expected population'], ['Target keys', 'Loaded population'], ['Full comparison', 'Preserve both'], ['Classification', 'Matched, missing, extra, conflict']] },
    { id: 'row-multiplication', title: 'Detecting row multiplication', objective: 'Find and prevent duplicate expansion caused by one-to-many and many-to-many joins.', model: 'A join returns every matching combination. If both sides contain duplicate join keys, row counts multiply. This may be correct for detailed analysis but destructive for metrics.', standard: 'Profile key uniqueness before joining and compare row counts before and after each join.', mistakes: ['Using DISTINCT to hide unexplained multiplication', 'Joining claims directly to multiple measure rows', 'Skipping intermediate counts'], scenario: ['Paid amount triples', 'Claims join to three quality measures per member.', 'Aggregate or select the relevant measure before joining, then verify totals.'], lab: ['Create an intentional many-to-many join.', 'Measure multiplication.', 'Fix with pre-aggregation.', 'Verify control totals.'], sourceKeys: ['postgres', 'duckdb'], visual: [['Left key count', 'Duplicates per key'], ['Right key count', 'Duplicates per key'], ['Join combinations', 'Left × right matches'], ['Control total', 'Detect inflation']] },
    { id: 'join-debugging', title: 'Debugging missing and incorrect joins', objective: 'Troubleshoot data type, formatting, effective-date, and composite-key problems.', model: 'Join failures often come from whitespace, case, type mismatch, leading zeros, inactive relationships, date-effective mappings, or incomplete composite keys. Normalizing blindly can create false matches.', standard: 'Inspect representative unmatched values and validate the full business key before transforming.', mistakes: ['Trimming and uppercasing every identifier without analysis', 'Joining on name instead of stable ID', 'Ignoring effective dates'], scenario: ['Store 00123 does not match 123', 'One source treated the ID as numeric.', 'Correct the upstream type or use a documented safe mapping, not an unreviewed cast.'], lab: ['Profile unmatched keys.', 'Compare types and lengths.', 'Test composite key.', 'Document root cause.'], sourceKeys: ['postgres', 'informatica'], visual: [['Unmatched rows', 'Visible exception set'], ['Profile values', 'Type, length, format'], ['Test business key', 'All required fields'], ['Correct cause', 'Source, mapping, or query']] },
  ]},
  { id: 'm6', title: 'CASE, Null Handling, and Data Cleaning', order: 6, lessons: [
    { id: 'case', title: 'CASE expressions and business classification', objective: 'Translate ordered business rules into transparent SQL categories.', model: 'CASE evaluates conditions in order and returns the first matching result. Rule order matters when conditions overlap. An ELSE branch makes unclassified data visible.', standard: 'Write rules in plain language first, order from most specific to general, and include an explicit unknown category.', mistakes: ['Overlapping rules in the wrong order', 'No ELSE branch', 'Embedding undocumented policy in SQL'], scenario: ['Readiness classification', 'Classify implementations as ready, at risk, blocked, or unknown.', 'Use explicit conditions and expose missing evidence as unknown rather than ready.'], lab: ['Build readiness CASE.', 'Test boundary values.', 'Add unknown category.', 'Compare category totals.'], sourceKeys: ['postgres', 'sqlite'], visual: [['Condition 1', 'Most specific'], ['Condition 2', 'Next rule'], ['First match', 'Returned category'], ['ELSE', 'Visible exception']] },
    { id: 'null-logic', title: 'Nulls and three-valued logic', objective: 'Predict how null affects comparison, boolean logic, aggregates, and joins.', model: 'Null represents missing or unknown information. Comparisons with null produce unknown, not true or false. WHERE keeps only true rows. Aggregates often ignore null values, which can silently change denominators.', standard: 'Define what missing means for each field and test null behavior explicitly.', mistakes: ['Using = NULL', 'Treating null as zero', 'Using NOT IN with nullable subquery values'], scenario: ['Missing target dates vanish', 'A NOT condition excludes null target dates unexpectedly.', 'Handle null explicitly and classify missing dates separately.'], lab: ['Predict null expressions.', 'Compare COUNT(*) and COUNT(column).', 'Fix NOT IN behavior.', 'Create missing-data flags.'], sourceKeys: ['postgres', 'sqlite'], visual: [['Comparison', 'True, false, or unknown'], ['WHERE', 'Keeps true only'], ['Aggregate', 'Often ignores null'], ['Policy', 'Define missing meaning']] },
    { id: 'coalesce-cleaning', title: 'COALESCE, standardization, and safe cleaning', objective: 'Provide fallback values without masking critical missing data.', model: 'COALESCE returns the first non-null expression. It is useful for display and controlled fallback, but replacing missing values can hide quality issues. Text normalization should preserve raw values and produce a separate standardized field.', standard: 'Flag missing critical fields before applying presentation defaults.', mistakes: ['Replacing every null with zero', 'Overwriting raw data', 'Using fallback from a non-authoritative source'], scenario: ['Unknown defect owner', 'A dashboard replaces missing owner with Operations.', 'Display Unassigned and retain a quality flag rather than assigning false ownership.'], lab: ['Create display fallback.', 'Create missing flag.', 'Normalize whitespace.', 'Preserve raw value.'], sourceKeys: ['postgres', 'sqlite'], visual: [['Raw field', 'Original evidence'], ['Quality flag', 'Missing or malformed'], ['Normalized field', 'Controlled transformation'], ['Display value', 'Optional fallback']] },
    { id: 'duplicates', title: 'Duplicate detection and survivorship', objective: 'Identify exact and business duplicates and define which record survives.', model: 'Exact duplicates repeat every field, while business duplicates share a key but differ in other attributes. Deleting duplicates requires a survivorship rule based on source authority, recency, completeness, or status.', standard: 'Quantify duplicates, preserve evidence, define survivorship, and prevent recurrence upstream.', mistakes: ['Using DISTINCT as remediation', 'Deleting without retained evidence', 'Choosing latest timestamp without source trust'], scenario: ['Duplicate eligibility periods', 'Two records share member, payer, and effective date but differ in termination date.', 'Investigate source and define a deterministic survivorship rule before exclusion.'], lab: ['Find exact duplicates.', 'Find business duplicates.', 'Rank candidates.', 'Produce survivor and exception sets.'], sourceKeys: ['postgres', 'duckdb'], visual: [['Candidate key', 'Business identity'], ['Duplicate group', 'More than one row'], ['Survivorship rule', 'Authority and recency'], ['Outcome', 'Survivor plus exception evidence']] },
  ]},
  { id: 'm7', title: 'Subqueries and Common Table Expressions', order: 7, lessons: [
    { id: 'scalar-subqueries', title: 'Scalar and list subqueries', objective: 'Use subqueries when one query depends on a calculated value or set.', model: 'A scalar subquery returns one value, while a list subquery returns a set used by IN or comparison operators. Correlated subqueries run in relation to an outer row and can be expensive or hard to reason about.', standard: 'Confirm expected cardinality of every subquery and prefer readable joins or CTEs when they make logic clearer.', mistakes: ['Scalar subquery returning multiple rows', 'NOT IN with null values', 'Using correlated subqueries without performance review'], scenario: ['Above-average defect rate', 'Find clients whose rate exceeds the portfolio average.', 'Calculate the benchmark once and compare client-level metrics against it.'], lab: ['Write scalar benchmark query.', 'Use list subquery.', 'Test null behavior.', 'Rewrite one as a join.'], sourceKeys: ['postgres', 'sqlite'], visual: [['Inner query', 'Produces value or set'], ['Outer query', 'Consumes result'], ['Cardinality', 'Must match operator'], ['Validation', 'Test independently']] },
    { id: 'exists', title: 'EXISTS and anti-existence patterns', objective: 'Test whether related records exist without multiplying rows.', model: 'EXISTS returns true when the subquery finds at least one qualifying row. It is often clearer than joining when the question is simply whether a relationship exists. NOT EXISTS is a null-safe anti-join pattern.', standard: 'Use EXISTS for presence tests and select a constant in the subquery to emphasize that returned columns do not matter.', mistakes: ['Joining and then using DISTINCT for presence', 'Using NOT IN against nullable values', 'Forgetting correlation condition'], scenario: ['Implementations without milestones', 'Find active implementations lacking a validation milestone.', 'Use NOT EXISTS correlated by implementation ID and milestone type.'], lab: ['Find clients with defects.', 'Find implementations without milestones.', 'Compare to join pattern.', 'Explain row-count behavior.'], sourceKeys: ['postgres', 'sqlite'], visual: [['Outer row', 'Candidate entity'], ['Related search', 'Correlated subquery'], ['Any match?', 'EXISTS boolean'], ['Keep or exclude', 'Presence rule']] },
    { id: 'ctes', title: 'Common table expressions for readable analysis', objective: 'Break complex SQL into named, testable steps.', model: 'A CTE names an intermediate result for use in the following statement. It improves readability and supports stepwise validation. It is not automatically faster and may be optimized differently by each database.', standard: 'Give CTEs business-meaningful names and validate row counts and grain at each step.', mistakes: ['Creating a chain without testing steps', 'Assuming CTE means cached', 'Using generic names such as temp1'], scenario: ['Release certification query', 'One query must validate counts, duplicates, dates, and mappings.', 'Use separate named CTEs for each control and combine them into a final decision.'], lab: ['Refactor a nested query.', 'Name each business step.', 'Document grain.', 'Add control counts.'], sourceKeys: ['postgres', 'duckdb'], visual: [['CTE 1', 'Eligible source rows'], ['CTE 2', 'Quality controls'], ['CTE 3', 'Aggregated results'], ['Final SELECT', 'Decision output']] },
    { id: 'query-decomposition', title: 'Decomposing and reviewing complex queries', objective: 'Turn monolithic SQL into reviewable, testable components.', model: 'Complexity becomes manageable when each transformation has a purpose, input grain, output grain, and validation. Temporary views, CTEs, and saved test queries can make review easier.', standard: 'Review logic in dependency order and keep a small known-answer fixture for regression testing.', mistakes: ['Changing many steps at once', 'Reviewing only final output', 'No known-answer examples'], scenario: ['Executive dashboard mismatch', 'A 300-line query produces unexplained counts.', 'Separate source eligibility, relationship joins, metric calculations, and presentation.'], lab: ['Split a long query.', 'Validate each step.', 'Create known-answer fixture.', 'Document assumptions.'], sourceKeys: ['postgres', 'duckdb'], visual: [['Source eligibility', 'Who belongs'], ['Transformation', 'How values change'], ['Metric logic', 'Numerator and denominator'], ['Presentation', 'Final labels and order']] },
  ]},
  { id: 'm8', title: 'Window Functions and Intermediate Analysis', order: 8, lessons: [
    { id: 'window-model', title: 'Window function mental model', objective: 'Understand partitions, ordering, frames, and why rows remain visible.', model: 'Window functions calculate across related rows without collapsing them into one group. PARTITION BY defines independent groups, ORDER BY defines sequence, and the frame defines which rows contribute to calculations.', standard: 'State partition, order, and frame in plain language before writing the expression.', mistakes: ['Confusing window functions with GROUP BY', 'Omitting deterministic order', 'Ignoring default frame behavior'], scenario: ['Latest implementation status', 'Keep every status event while showing sequence and latest flag.', 'Partition by implementation and order by event timestamp with a tie breaker.'], lab: ['Add row numbers.', 'Calculate running count.', 'Change partition.', 'Explain output grain.'], sourceKeys: ['postgres', 'duckdb'], visual: [['Partition', 'Independent group'], ['Order', 'Sequence within group'], ['Frame', 'Rows considered'], ['Function', 'Value without collapsing rows']] },
    { id: 'ranking', title: 'ROW_NUMBER, RANK, and latest-record patterns', objective: 'Choose ranking functions and select deterministic latest records.', model: 'ROW_NUMBER assigns a unique sequence. RANK leaves gaps after ties, while DENSE_RANK does not. Latest-record logic usually uses ROW_NUMBER with complete ordering.', standard: 'Include a stable tie breaker and retain duplicate candidates for investigation.', mistakes: ['Using MAX(date) and losing other columns', 'Ignoring tied timestamps', 'Deleting rows ranked above one without review'], scenario: ['Latest milestone', 'Two updates share the same timestamp.', 'Order by timestamp and event ID, then flag ambiguity if needed.'], lab: ['Rank defects by client.', 'Select latest milestone.', 'Compare rank functions.', 'Test ties.'], sourceKeys: ['postgres', 'duckdb'], visual: [['Partition', 'One implementation'], ['Order', 'Newest first'], ['ROW_NUMBER', 'Unique sequence'], ['Filter', 'rn = 1 latest row']] },
    { id: 'lag-lead', title: 'LAG, LEAD, and change analysis', objective: 'Compare each row to previous or next values.', model: 'LAG and LEAD access neighboring rows within a window. They support change detection, duration calculation, and period comparison without self-joins.', standard: 'Define the business sequence and handle the first or last row where no neighbor exists.', mistakes: ['Ordering by an unstable field', 'Comparing across partitions', 'Treating missing prior row as zero automatically'], scenario: ['Week-over-week release volume', 'Flag changes greater than twenty percent.', 'Use LAG by client ordered by release date, then calculate controlled percentage change.'], lab: ['Calculate prior volume.', 'Calculate change.', 'Flag threshold.', 'Handle first period.'], sourceKeys: ['postgres', 'duckdb'], visual: [['Current row', 'This release'], ['LAG', 'Prior release'], ['Difference', 'Absolute change'], ['Rate', 'Controlled percentage change']] },
    { id: 'running-metrics', title: 'Running totals and rolling metrics', objective: 'Calculate cumulative and moving-window measures safely.', model: 'Running totals accumulate values through the current row. Rolling metrics use a bounded frame such as the current and prior six rows. Calendar gaps can make row-based windows differ from date-based expectations.', standard: 'Specify frame explicitly and test missing periods and duplicate dates.', mistakes: ['Relying on default frame', 'Assuming rows equal calendar periods', 'Double-counting after joins'], scenario: ['Cumulative implementation launches', 'Show launches by month and year-to-date total.', 'Aggregate to month first, then apply a running sum ordered by month.'], lab: ['Build monthly counts.', 'Add cumulative total.', 'Add three-period average.', 'Test missing month.'], sourceKeys: ['postgres', 'duckdb'], visual: [['Aggregate period', 'One row per month'], ['Order periods', 'Calendar sequence'], ['Frame', 'Start through current'], ['Window metric', 'Cumulative or rolling']] },
  ]},
  { id: 'm9', title: 'Data Reconciliation, Validation, and Release Certification', order: 9, lessons: [
    { id: 'control-totals', title: 'Control totals and source-target reconciliation', objective: 'Prove completeness using counts, distinct keys, sums, and classification.', model: 'Control totals are independent checks that compare source and target populations. Strong reconciliation includes row count, distinct business keys, important amount totals, date ranges, and matched/source-only/target-only classification.', standard: 'Define tolerances before validation and preserve evidence for every release.', mistakes: ['Comparing only row count', 'Using transformed target as the source control', 'Changing tolerance after seeing results'], scenario: ['Two missing records', 'Counts differ by two but paid totals match.', 'Identify exact records and disposition them; matching totals do not prove completeness.'], lab: ['Build control totals.', 'Reconcile by key.', 'Classify differences.', 'Write release evidence.'], sourceKeys: ['postgres', 'snowflake'], visual: [['Source controls', 'Expected totals'], ['Target controls', 'Loaded totals'], ['Key reconciliation', 'Record-level comparison'], ['Disposition', 'Explain every variance']] },
    { id: 'quality-rules', title: 'Data-quality rules and exception reporting', objective: 'Implement completeness, validity, uniqueness, consistency, and timeliness checks.', model: 'A quality rule should define the data element, condition, severity, threshold, owner, and remediation. Exception queries should return actionable records, not only a failed count.', standard: 'Separate rule outcome from business disposition and version rules with release changes.', mistakes: ['Writing rules without owner', 'Returning only aggregate counts', 'Treating every exception as equal severity'], scenario: ['Invalid eligibility dates', 'Some termination dates precede effective dates.', 'Return affected records, quantify rate, assign severity, and block release if threshold is exceeded.'], lab: ['Create five rules.', 'Return exception detail.', 'Calculate rate.', 'Assign threshold and owner.'], sourceKeys: ['postgres', 'informatica'], visual: [['Rule', 'Condition and field'], ['Exception set', 'Actionable records'], ['Threshold', 'Pass, warning, fail'], ['Owner', 'Remediation responsibility']] },
    { id: 'release-comparison', title: 'Current-versus-prior release analysis', objective: 'Detect unexpected changes without assuming every difference is a defect.', model: 'Release comparison examines volume, membership, dates, financial totals, status distribution, and key-level additions and removals. Expected business changes should be documented so anomaly detection does not become noise.', standard: 'Use consistent cutoffs and calculate absolute and percentage change with protection against zero denominators.', mistakes: ['Comparing partial current data to complete prior data', 'Flagging every new record', 'Ignoring large changes hidden by stable totals'], scenario: ['Stable total, changed members', 'Current and prior counts match but 500 IDs changed.', 'Perform key-level churn analysis instead of relying on total count.'], lab: ['Compare two releases.', 'Calculate churn.', 'Flag volume threshold.', 'Explain expected changes.'], sourceKeys: ['postgres', 'snowflake'], visual: [['Prior release', 'Baseline'], ['Current release', 'Candidate'], ['Aggregate variance', 'Counts and amounts'], ['Key churn', 'Adds and removals'], ['Decision', 'Expected or anomalous']] },
    { id: 'certification-decision', title: 'Release certification and go/no-go logic', objective: 'Combine controls into a defensible release recommendation.', model: 'Certification converts validation evidence into a decision. A go means all blocking criteria pass. Conditional go requires explicit accepted risk, owner, and deadline. No-go means release risk exceeds approved tolerance.', standard: 'Define decision rules before execution and separate evidence generation from approval authority.', mistakes: ['Calling conditional go without owner', 'Allowing warnings to accumulate silently', 'Using personal judgment without thresholds'], scenario: ['One blocking mapping defect', 'A payer mapping is missing for a high-volume pharmacy.', 'Recommend no-go or formal conditional approval only if impact, workaround, owner, and deadline are accepted by authority.'], lab: ['Combine control results.', 'Assign severity.', 'Calculate readiness.', 'Write executive recommendation.'], sourceKeys: ['snowflake', 'informatica'], visual: [['Controls', 'Measured evidence'], ['Thresholds', 'Pass, warning, fail'], ['Risk acceptance', 'Owner and deadline'], ['Decision', 'Go, conditional, no-go']] },
  ]},
  { id: 'm10', title: 'Snowflake Navigation and Query Operations', order: 10, lessons: [
    { id: 'snowflake-hierarchy', title: 'Accounts, databases, schemas, and objects', objective: 'Navigate Snowflake context and fully qualified object names.', model: 'A Snowflake account contains databases. Databases contain schemas, and schemas contain tables, views, stages, functions, and other objects. The active role and current database, schema, and warehouse determine what a worksheet can access and execute.', standard: 'Verify role, warehouse, database, and schema before running implementation queries.', mistakes: ['Assuming the worksheet context is unchanged', 'Using an unqualified table name across environments', 'Confusing database and warehouse'], scenario: ['Object not found', 'The table exists but the worksheet uses another database and role.', 'Inspect current context and privileges before escalating.'], lab: ['Map object hierarchy.', 'Write fully qualified names.', 'Inspect current context.', 'Explain database versus warehouse.'], sourceKeys: ['snowflake'], visual: [['Account', 'Security and regional boundary'], ['Database', 'Data collection'], ['Schema', 'Namespace'], ['Object', 'Table, view, stage'], ['Warehouse', 'Independent compute']] },
    { id: 'warehouses-roles', title: 'Warehouses, roles, and cost-aware querying', objective: 'Explain compute selection, privileges, suspension, and common permission failures.', model: 'Virtual warehouses provide compute and can be resized, suspended, and resumed independently of storage. Roles receive privileges on objects and warehouses. Larger warehouses may finish faster but cost more per unit time.', standard: 'Use the approved role and appropriately sized warehouse, filter early, avoid unnecessary scans, and stop abandoned work.', mistakes: ['Using the largest warehouse by default', 'Assuming role inheritance', 'Leaving long-running queries unattended'], scenario: ['Permission denied', 'A learner can see a database but cannot query a table.', 'Check USAGE on database/schema, SELECT on object, and warehouse privileges.'], lab: ['Diagnose permission scenarios.', 'Choose warehouse size rationale.', 'Review query scan.', 'Document role request.'], sourceKeys: ['snowflake'], visual: [['Role', 'Granted privileges'], ['Warehouse', 'Compute resource'], ['Database object', 'Stored data'], ['Query', 'Requires both access and compute']] },
    { id: 'worksheets-history', title: 'Worksheets, result sets, and query history', objective: 'Use Snowsight to run, inspect, save, and troubleshoot queries.', model: 'Worksheets organize SQL and context. Result sets can be inspected and downloaded under governance controls. Query history records text, timing, status, warehouse, user, and profile details useful for troubleshooting.', standard: 'Name worksheets, add comments, preserve validation queries, and capture query IDs for support evidence.', mistakes: ['Sharing result downloads with sensitive data', 'Overwriting validated SQL without version history', 'Sending screenshots without query ID'], scenario: ['Slow release query', 'The same query became much slower this week.', 'Compare query history, profile, scanned data, warehouse, and plan changes.'], lab: ['Run a validation query.', 'Locate query history.', 'Capture query ID.', 'Interpret one profile indicator.'], sourceKeys: ['snowflake'], visual: [['Worksheet', 'SQL and context'], ['Execution', 'Warehouse processes'], ['Result set', 'Returned rows'], ['Query history', 'Evidence and profile']] },
    { id: 'stages-time-travel', title: 'Stages, loading, cloning, and Time Travel awareness', objective: 'Recognize core Snowflake operational features without overclaiming engineering depth.', model: 'Stages hold files for loading or unloading. COPY INTO loads staged data. Zero-copy cloning creates metadata-based copies without immediately duplicating storage. Time Travel can query or restore historical object states within configured retention.', standard: 'Implementation leaders should understand purpose, ownership, retention, and cost implications, while partnering with engineers for production design.', mistakes: ['Treating a stage as a final table', 'Assuming clones remain free forever', 'Assuming Time Travel is an unlimited backup'], scenario: ['Bad transformation deployed', 'A curated table changed unexpectedly.', 'Use documented recovery procedures and historical comparison within available retention, not ad hoc production edits.'], lab: ['Describe a staged load.', 'Map COPY flow.', 'Explain clone use.', 'State Time Travel limits.'], sourceKeys: ['snowflake'], visual: [['Stage', 'Files awaiting load'], ['COPY', 'Ingestion command'], ['Table', 'Structured target'], ['Clone', 'Fast isolated copy'], ['Time Travel', 'Historical state within retention']] },
  ]},
  { id: 'm11', title: 'SQL Troubleshooting, Informatica, AI Assistance, and Capstone', order: 11, lessons: [
    { id: 'informatica-bridge', title: 'SQL across Informatica mappings and taskflows', objective: 'Use SQL to validate sources, transformations, targets, rejects, and lineage.', model: 'Informatica connects sources and targets through mappings, transformations, tasks, and taskflows. SQL validates populations before ingestion, after transformation, and in rejected-record stores. A mapping failure can be connection, schema, permission, transformation, data, or orchestration related.', standard: 'Capture source controls, mapping version, task run ID, target controls, reject counts, and representative errors.', mistakes: ['Calling every pipeline issue a SQL defect', 'Validating only final row count', 'Ignoring rejected records'], scenario: ['Target count short by 42', 'The task succeeded but records are missing.', 'Inspect rejects, lookup outcomes, filters, and source-target controls by rule.'], lab: ['Map source-to-target flow.', 'Write pre-load controls.', 'Write post-load controls.', 'Reconcile rejects.'], sourceKeys: ['informatica', 'snowflake'], visual: [['Source', 'Input population'], ['Mapping', 'Transformations and lookups'], ['Taskflow', 'Execution order'], ['Target', 'Loaded rows'], ['Rejects', 'Failed records'], ['SQL controls', 'Evidence at each stage']] },
    { id: 'query-performance', title: 'Query performance and safe troubleshooting', objective: 'Explain scan reduction, filters, joins, statistics, and execution plans at an implementation-leader level.', model: 'Performance depends on data volume, selected columns, filters, join strategy, clustering or indexes, warehouse resources, concurrency, and engine optimization. Slow does not automatically mean incorrect.', standard: 'Reproduce safely, capture query ID and timing, inspect scanned rows, reduce unnecessary data, and partner with platform engineers before structural changes.', mistakes: ['Adding DISTINCT as a performance fix', 'Running destructive experiments in production', 'Blaming warehouse size without profiling'], scenario: ['Validation query times out', 'A join scans years of claims for a weekly release.', 'Filter to the release population early and pre-aggregate before joining.'], lab: ['Identify expensive patterns.', 'Add early filter.', 'Reduce selected columns.', 'Compare execution evidence.'], sourceKeys: ['postgres', 'snowflake'], visual: [['Query text', 'Requested work'], ['Optimizer', 'Execution strategy'], ['Scan and join', 'Major cost drivers'], ['Profile', 'Evidence for improvement']] },
    { id: 'ai-assisted-sql', title: 'AI-assisted SQL with independent validation', objective: 'Use AI to accelerate drafting while controlling schema, privacy, logic, and destructive risk.', model: 'AI can propose SQL, explain syntax, generate test cases, and identify edge cases. It can also hallucinate tables, invent relationships, multiply rows, mishandle nulls, or produce destructive statements. The learner remains accountable for correctness.', standard: 'Provide approved schema and business rules, request an explanation, run read-only on small fixtures, validate grain, joins, nulls, totals, and expected outputs, and never paste sensitive production data into unapproved tools.', mistakes: ['Trusting plausible syntax', 'Providing confidential data', 'Running generated DELETE or UPDATE statements'], scenario: ['Hallucinated column', 'AI uses payer_name on claims where only payer_id exists.', 'Reject the query, supply the actual schema, and validate every referenced object.'], lab: ['Prompt with schema.', 'Ask for explanation.', 'Test known-answer fixture.', 'Validate joins and nulls.', 'Document AI review checklist.'], sourceKeys: ['postgres', 'snowflake'], visual: [['Schema and rules', 'Grounded prompt'], ['Generated draft', 'Untrusted proposal'], ['Read-only test', 'Small known fixture'], ['Validation', 'Grain, joins, nulls, totals'], ['Approval', 'Human accountability']] },
    { id: 'capstone-release-certification', title: 'Healthcare Implementation Release Certification capstone', objective: 'Produce a complete SQL evidence package and defend a go, conditional-go, or no-go recommendation.', model: 'The capstone validates a weekly payer and pharmacy release using schema inspection, source-target reconciliation, duplicate checks, required fields, date logic, mappings, prior-release comparison, volume thresholds, control totals, and defect disposition.', standard: 'Every conclusion must be traceable to a saved query, threshold, exception set, owner, and decision rule.', mistakes: ['Making a recommendation from aggregate counts alone', 'Ignoring unresolved high-severity defects', 'Writing an executive summary without evidence links'], scenario: ['Weekly production release', 'Current data includes duplicate eligibility, invalid dates, missing mappings, and a twelve-percent volume decline.', 'Run the full control suite and recommend based on predefined severity and thresholds.'], lab: ['Execute schema inspection.', 'Run reconciliation and quality checks.', 'Compare prior release.', 'Build certification result.', 'Write executive summary and STAR story.'], sourceKeys: ['postgres', 'snowflake', 'informatica'], visual: [['Inspect', 'Schema and grain'], ['Reconcile', 'Source and target'], ['Validate', 'Quality rules'], ['Compare', 'Prior release'], ['Disposition', 'Defects and owners'], ['Certify', 'Go, conditional, no-go']] },
  ]},
]

function lessonVisual(lesson: Blueprint): LessonVisual {
  const source = sources[lesson.sourceKeys[0]]
  return { title: `${lesson.title}: visual model`, caption: `Original Orivo Health Academy visual adapted from ${source.publisher} documentation.`, steps: lesson.visual.map(([label, detail]) => ({ label, detail })), sourceLabel: source.label, sourceUrl: source.url }
}

export const sqlLessons: FullLesson[] = modules.flatMap((module) => module.lessons.map((lesson, index) => ({
  id: lesson.id,
  courseId: 'sql-product-implementation',
  moduleId: module.id,
  moduleTitle: module.title,
  moduleOrder: module.order,
  lessonOrder: index + 1,
  title: lesson.title,
  objective: lesson.objective,
  sections: [
    { heading: 'Core model', paragraphs: [lesson.model] },
    { heading: 'Implementation standard', paragraphs: [lesson.standard] },
    { heading: 'Common failure patterns', paragraphs: ['Use these as review prompts before trusting a result.'], bullets: lesson.mistakes },
  ],
  visual: lessonVisual(lesson),
  scenario: { title: lesson.scenario[0], context: lesson.scenario[1], decision: 'What should the implementation leader do next?', recommendedApproach: lesson.scenario[2] },
  lab: { title: `${lesson.title} lab`, brief: 'Use the synthetic Orivo healthcare implementation database and save the query plus interpretation.', steps: lesson.lab, evidence: ['SQL file or saved worksheet', 'Result screenshot or exported CSV with synthetic data', 'Plain-language interpretation', 'One risk and one validation'], answerGuide: ['Confirm the intended grain.', 'Validate row counts before and after joins.', 'Explain null and duplicate behavior.', 'Use only synthetic course data.'] },
  keyTakeaways: [lesson.objective, lesson.standard, lesson.mistakes[0]],
  sources: lesson.sourceKeys.map((key) => sources[key]),
})))

export const sqlModules = modules.map((module) => ({ id: module.id, title: module.title, order: module.order, lessons: module.lessons.map((lesson) => lesson.id) }))
export const sqlCapstone = { title: 'Healthcare Implementation Release Certification', description: 'Validate a weekly payer and pharmacy release and produce a defensible go, conditional-go, or no-go recommendation.', artifacts: ['SQL query package', 'Data-quality checklist', 'Reconciliation report', 'Defect summary', 'Release certification result', 'Executive communication', 'Interview-ready STAR story'] }
